const logoutBtn=document.getElementById("logoutBtn");logoutBtn&&(logoutBtn.onclick=async function(){localStorage.removeItem("token");try{await fetch("https://alexokoriengobe.onrender.com/api/auth/logout",{method:"POST",headers:{Authorization:`Bearer ${localStorage.getItem("token")}`,"Content-Type":"application/json"},credentials:"include"})}catch(t){}window.location.href="login.html"});